import { useEffect, useState } from "react";
import axios from "axios";

export default function Dashboard() {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [confirming, setConfirming] = useState(null);

  const fetchData = async () => {
    setLoading(true);
    setError("");
    try {
      const res = await axios.get("http://localhost:5000/api/dashboard");
      setData(res.data);
    } catch (err) {
      setError("Failed to load dashboard.");
    }
    setLoading(false);
  };

  const confirm = async (id) => {
    setConfirming(id);
    try {
      await axios.post("http://localhost:5000/api/confirm", { id });
      fetchData();
    } catch (err) {
      setError("Failed to confirm item.");
    }
    setConfirming(null);
  };

  useEffect(() => {
    fetchData();
  }, []);

  return (
    <div className="card">
      <h3>Dashboard</h3>
      {loading && <p>Loading...</p>}
      {error && <p className="error">{error}</p>}
      {!loading && !error && data.length === 0 && <p>No waste items found.</p>}
      {!loading && !error && data.map((d) => (
        <div key={d.id} className="item">
          <p><b>Type:</b> {d.type}</p>
          <p><b>Disposal Section:</b> {d.section}</p>
          <p><b>Status:</b> {d.status}</p>
          <p><b>Uploaded:</b> {new Date(d.time).toLocaleString()}</p>
          {d.status === "Pending" && (
            <button onClick={() => confirm(d.id)} disabled={confirming === d.id}>
              {confirming === d.id ? "Confirming..." : "Confirm Disposal"}
            </button>
          )}
        </div>
      ))}
    </div>
  );
}
